import jwt from 'jsonwebtoken';
import { db } from './db';

export const verifyToken = (token: string) => jwt.verify(token, process.env.JWT_SECRET!);

export async function refreshToken(refreshToken: string) {
  const stored = await db.refreshTokens.findOne({ token: refreshToken });
  if (!stored || stored.expiresAt < new Date()) throw new Error('Invalid refresh token');
  const accessToken = jwt.sign({ userId: stored.userId }, process.env.JWT_SECRET!, { expiresIn: '15m' });
  return { accessToken };
}

// Token refresh route handler
export const tokenRefreshHandler = async (req, res) => {
  const { refreshToken } = req.body;
  const result = await refreshToken(refreshToken);
  res.json(result);
};
